code = """import json
import re

# Load data from stored files
civic_path = locals()['var_functions.query_db:26']
funding_path = locals()['var_functions.query_db:32']

with open(civic_path, 'r') as f:
    civic_docs = json.load(f)

with open(funding_path, 'r') as f:
    funding_data = json.load(f)

# Identify disaster projects that started in 2022 from civic documents
disaster_2022_projects = set()

for doc in civic_docs:
    text = doc.get('text', '')
    # Find lines with disaster indicators and 2022
    for line in text.split('\n'):
        line_clean = line.strip()
        if any(indicator in line_clean for indicator in ['(FEMA', '(CalJPIA', '(CalOES']):
            # Check surrounding context for 2022 dates
            if '2022' in text:
                # Extract project name (usually the line itself for disaster projects)
                proj_name = re.sub('\s+', ' ', line_clean)
                if len(proj_name) > 5:  # Filter out noise
                    disaster_2022_projects.add(proj_name)

print('Disaster projects with 2022 references:', len(disaster_2022_projects))

# Match with funding data
total_funding = 0
matched_projects = []

for proj in disaster_2022_projects:
    for fund in funding_data:
        fund_name = fund['Project_Name']
        # Match if project name is contained in funding name or vice versa
        if proj in fund_name or fund_name in proj:
            amount = int(fund['Amount'])
            total_funding += amount
            matched_projects.append(fund_name)

print('Matched projects:', len(matched_projects))
print('Total funding:', total_funding)

result = {'total_funding': total_funding}
print('__RESULT__:')
print(json.dumps(result))"""

